<span style={{padding:"3px 8px",borderRadius:8,background:`${(BORTLE_COL[rd.bo]||"#888")}15`,border:`1px solid ${(BORTLE_COL[rd.bo]||"#888")}30`,fontSize:9.5,color:BORTLE_COL[rd.bo]||"#888"}}>{rd.bN}</span></div></div>
<div style={{display:"flex",gap:2,marginBottom:10}}>{[1,2,3,4,5,6,7,8,9].map(b=><div key={b} style={{flex:1,height:8,borderRadius:4,background:b<=rd.bo?"rgba(255,255,255,.06)":(BORTLE_COL[b]||"#444"),opacity:b<=rd.bo?1:.2,transition:"all .2s"}}/>)}</div>
