          <button onClick={()=>{setShowS(!showS);setShowV(false);setShowR(false)}} style={{flex:1,padding:"7px 10px",borderRadius:11,background:sortKey?"rgba(200,180,120,.05)":"rgba(255,255,255,.02)",border:sortKey?"1px solid rgba(200,180,120,.18)":"1px solid rgba(255,255,255,.05)",color:sortKey?"#e8d5a0":"rgba(255,255,255,.28)",fontSize:10.5,cursor:"pointer"}}>↕ {sortKey?sortKey.l:"Sort By"}</button>
          {(vibeF!=="All"||sortKey)&&<button onClick={()=>{setVibeF("All");setSortKey(null)}} style={{padding:"7px 10px",borderRadius:11,background:"rgba(239,68,68,.05)",border:"1px solid rgba(239,68,68,.15)",color:"rgba(239,68,68,.55)",fontSize:10.5,cursor:"pointer"}}>✕</button>}
