        {showS&&<div style={{display:"flex",flexWrap:"wrap",gap:4,marginTop:6,animation:"fi .12s ease",padding:3}}>{sortOpts.map(s=><button key={s.l} onClick={()=>{setSortKey(sortKey?.l===s.l?null:s);setShowS(false)}} style={{padding:"5px 10px",borderRadius:11,background:sortKey?.l===s.l?"rgba(200,180,120,.07)":"rgba(255,255,255,.012)",border:sortKey?.l===s.l?"1px solid rgba(200,180,120,.22)":"1px solid rgba(255,255,255,.035)",color:sortKey?.l===s.l?"#e8d5a0":"rgba(255,255,255,.25)",fontSize:10,cursor:"pointer"}}>{s.l}</button>)}</div>}
